-- Seed: Joiin per-entity standalone P&L (Phase 18) — by-company
-- Standalone (un-eliminated) P&L per group company, from the Joiin by-company report.
-- Drives the board-pack per-entity views. Idempotent. Run after migration 021.
-- Covers 2026-06 (513 rows).

BEGIN;

DELETE FROM finance.joiin_pl_entity WHERE ym IN ('2026-06');

ON CONFLICT (entity_id, section, account, ym) DO UPDATE
  SET value = EXCLUDED.value, source = EXCLUDED.source, updated_by = EXCLUDED.updated_by, updated_at = CURRENT_TIMESTAMP;

COMMIT;
